import LocalAuthentication
import SwiftUI

class AuthenticationManager: ObservableObject {
    @Published var isAuthenticated: Bool {
        didSet {
            UserDefaults.standard.set(isAuthenticated, forKey: "isAuthenticated")
        }
    }

    init() {
        self.isAuthenticated = UserDefaults.standard.bool(forKey: "isAuthenticated")
    }

    func authenticateWithBiometrics(reason: String, completion: @escaping (Bool, String?) -> Void) {
        let context = LAContext()
        var error: NSError?

        if context.canEvaluatePolicy(.deviceOwnerAuthenticationWithBiometrics, error: &error) {
            context.evaluatePolicy(.deviceOwnerAuthenticationWithBiometrics, localizedReason: reason) { success, authenticationError in
                DispatchQueue.main.async {
                    if success {
                        self.isAuthenticated = true
                        completion(true, nil)
                    } else {
                        self.isAuthenticated = false
                        let errorMessage = authenticationError?.localizedDescription ?? "Unknown error"
                        completion(false, errorMessage)
                    }
                }
            }
        } else {
            self.isAuthenticated = false
            let errorMessage = error?.localizedDescription ?? "Biometric authentication not available or configured."
            completion(false, errorMessage)
        }
    }

    func logout() {
        isAuthenticated = false
    }
}

struct ContentView: View {
    @EnvironmentObject var authManager: AuthenticationManager

    var body: some View {
        Group {
            if authManager.isAuthenticated {
                HomeView()
            } else {
                LoginView()
            }
        }
    }
}

struct LoginView: View {
    @EnvironmentObject var authManager: AuthenticationManager
    @State private var username = ""
    @State private var password = ""
    @State private var showingBiometricAlert = false
    @State private var biometricAuthError: String?
    @State private var showingPasswordLoginError = false

    var body: some View {
        NavigationView {
            VStack(spacing: 20) {
                Spacer()

                Text("Welcome Back")
                    .font(.largeTitle)
                    .fontWeight(.bold)

                TextField("Username", text: $username)
                    .textFieldStyle(RoundedBorderTextFieldStyle())
                    .padding(.horizontal)
                    .autocapitalization(.none)
                    .disableAutocorrection(true)

                SecureField("Password", text: $password)
                    .textFieldStyle(RoundedBorderTextFieldStyle())
                    .padding(.horizontal)

                if showingPasswordLoginError {
                    Text("Invalid username or password.")
                        .foregroundColor(.red)
                }

                Button("Login") {
                    // Simulate a login attempt
                    if username == "user" && password == "password" {
                        authManager.isAuthenticated = true
                        showingPasswordLoginError = false
                    } else {
                        showingPasswordLoginError = true
                    }
                }
                .buttonStyle(PrimaryButtonStyle())

                Divider()
                    .padding(.horizontal)

                Button {
                    authenticateWithBiometrics()
                } label: {
                    HStack {
                        Image(systemName: LAContext().biometryType == .faceID ? "faceid" : "touchid")
                            .font(.title2)
                        Text("Authenticate with \(LAContext().biometryType == .faceID ? "Face ID" : "Touch ID")")
                    }
                }
                .buttonStyle(PrimaryButtonStyle())
                .alert("Biometric Authentication Failed", isPresented: $showingBiometricAlert, presenting: biometricAuthError) { error in
                    Button("Try Again") {
                        authenticateWithBiometrics()
                    }
                    Button("Enter Password") {
                        // User chose to enter password, do nothing, stay on login screen
                    }
                } message: { error in
                    Text(error)
                }

                Spacer()
            }
            .navigationTitle("Login")
            .navigationBarHidden(true)
            .onAppear {
                // Attempt biometric authentication automatically on appear if not already authenticated
                if !authManager.isAuthenticated {
                    authenticateWithBiometrics()
                }
            }
        }
    }

    private func authenticateWithBiometrics() {
        authManager.authenticateWithBiometrics(reason: "Unlock your app with biometrics") { success, error in
            if !success {
                biometricAuthError = error
                showingBiometricAlert = true
            }
            // If success, authManager.isAuthenticated is already set to true
        }
    }
}

